  public void testRefApp() {
    try {
      String output = "(ref 17)";
      String input = "let x := ref 10; in {x <- 17; x}";
      noNameCheck("refApp", output, input );
      nameNameCheck("refApp [name]", "(ref 10)", input);
    } catch (Exception e) {
      e.printStackTrace();
      fail("refApp threw " + e);
    }
  } //end of func
  
